dslRuleAfterChange:
($x$ || $y$ || $x$)
=> ($x$ || $y$)
;;

// Or a more generic version might be needed, which is even harder:
// $expr_1 $op $expr_2 $op $expr_1 => $expr_1 $op $expr_2

dslRule:
@id: performance.precompile.regex.declaration
@severity: info
final java.lang.String $var = $regexLiteral;
:: isRegexp($regexLiteral)
=> final java.util.regex.Pattern $var = java.util.regex.Pattern.compile($regexLiteral);
;;

// The following usage rules would be needed but cannot be safely expressed in the current DSL
// without advanced type propagation or multi-statement rewrite capabilities:
//
// $target.replaceFirst($regexVar, $replacement);
// :: instanceof($regexVar, "java.util.regex.Pattern") // This guard is problematic as $regexVar is 'String' in the pattern.
// => $regexVar.matcher($target).replaceFirst($replacement);
// ;;
//
// $target.replaceAll($regexVar, $replacement);
// :: instanceof($regexVar, "java.util.regex.Pattern") // This guard is problematic as $regexVar is 'String' in the pattern.
// => $regexVar.matcher($target).replaceAll($replacement);
// ;;

// Not safely implementable in current DSL without usage analysis.
